import React, { useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer,
} from "recharts";

export default function App() {
  const [file, setFile] = useState(null);
  const [fileId, setFileId] = useState("");
  const [summary, setSummary] = useState(null);
  const [chartData, setChartData] = useState([]);
  const [chartColumn, setChartColumn] = useState("");
  const [insights, setInsights] = useState([]);
  const [history, setHistory] = useState([]);
  const [selectedColumn, setSelectedColumn] = useState("");


 


  const handleUpload = async () => {
    if (!file) {
      alert("Please select CSV file first");
      return;
    }

    try {
      const formData = new FormData();
      formData.append("file", file);

      const uploadRes = await fetch("http://127.0.0.1:8000/api/upload", {
        method: "POST",
        body: formData,
      });

      const uploadData = await uploadRes.json();
      const uploadedFileId = uploadData.file_id;
      setFileId(uploadedFileId);

      const analyzeRes = await fetch(
        `http://127.0.0.1:8000/api/analyze/${uploadedFileId}`,
        { method: "POST" }
      );
      const analyzeData = await analyzeRes.json();
      setSummary(analyzeData.summary);

      const chartRes = await fetch(
        `http://127.0.0.1:8000/api/charts/${uploadedFileId}`
      );

      const chartJson = await chartRes.json();
      setChartData(chartJson.data || []);
      setChartColumn(chartJson.chart_column || "");
      setSelectedColumn(chartJson.chart_column || "");

      const insightRes = await fetch(
        `http://127.0.0.1:8000/api/insights/${uploadedFileId}`
      );
      const insightJson = await insightRes.json();
      setInsights(insightJson.insights || []);

      const historyRes = await fetch("http://127.0.0.1:8000/api/history");
      const historyJson = await historyRes.json();
      setHistory(historyJson.history || []);
    } catch (error) {
      console.error(error);
      alert("Something went wrong");
    }
  };

  const cardStyle = {
    background: "#fff",
    borderRadius: "12px",
    padding: "20px",
    boxShadow: "0 4px 10px rgba(0,0,0,0.08)",
    marginBottom: "20px",
  };

  return (
    <div
      style={{
        padding: "30px",
        fontFamily: "Arial",
        background: "#f5f7fb",
        minHeight: "100vh",
      }}
    >
      <h1 style={{ marginBottom: "20px" }}>AI CSV Analyzer Dashboard 📊</h1>

      <div style={cardStyle}>
        <input
          type="file"
          accept=".csv"
          onChange={(e) => setFile(e.target.files[0])}
        />
        <button
          onClick={handleUpload}
          style={{
            marginLeft: "10px",
            padding: "10px 16px",
            borderRadius: "8px",
            border: "none",
            cursor: "pointer",
          }}
        >
          Upload & Analyze
        </button>
      </div>

      {fileId && (
        <div style={cardStyle}>
          <b>File ID:</b> {fileId}
        </div>
      )}

      {summary && (
        <select
          value={selectedColumn}
          onChange={(e) => setSelectedColumn(e.target.value)}
          style={{
            marginBottom: "15px",
            padding: "8px",
            borderRadius: "8px",
          }}
        >
          {summary.columns
            .filter((col) =>
              ["revenue", "orders", "ad_spend"].includes(col)
            )
            .map((col) => (
              <option key={col} value={col}>
                {col}
              </option>
            ))}
        </select>
      )}
      
      {chartData.length > 0 && (
  <select
    value={selectedColumn}
    onChange={(e) => setSelectedColumn(e.target.value)}
    style={{
      marginBottom: "15px",
      padding: "8px",
      borderRadius: "8px",
    }}
  >
    {Object.keys(chartData[0])
      .filter((key) =>
        ["revenue", "orders", "ad_spend"].includes(key)
      )
      .map((col) => (
        <option key={col} value={col}>
          {col}
        </option>
      ))}
  </select>
)}

      {insights.length > 0 && (
        <div style={cardStyle}>
          <h2>AI Insights 🤖</h2>
          <ul>
            {insights.map((item, index) => (
              <li key={index}>{item}</li>
            ))}
          </ul>
        </div>
      )}

      {fileId && (
        <div style={cardStyle}>
          <a
            href={`http://127.0.0.1:8000/api/export/${fileId}`}
            target="_blank"
            rel="noreferrer"
          >
            <button
              style={{
                padding: "10px 16px",
                borderRadius: "8px",
                border: "none",
                cursor: "pointer",
              }}
            >
              Download Report 📥
            </button>
          </a>
        </div>
      )}

      {history.length > 0 && (
        <div style={cardStyle}>
          <h2>Upload History 🕘</h2>
          <ul>
            {history.map((item, index) => (
              <li key={index}>
                {item.filename} → {item.file_id}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
